// Resolve the current phase from the latest persisted state, falling back to parse-validate.
// This runs before Execute Phase in every loop iteration.
const phases = ['DISCOVER', 'STRATEGIZE', 'SCAFFOLD', 'BUILD', 'HARDEN', 'LAUNCH', 'OPERATE'];
let current_phase = null;
try { current_phase = $node['Advance to Next Phase'].json.current_phase; } catch(e) {}
if (!current_phase) {
  try { current_phase = $node['Parse & Validate Request'].json.current_phase; } catch(e) {}
}
current_phase = current_phase || 'DISCOVER';
let parsed = {};
try { parsed = $node['Parse & Validate Request'].json || {}; } catch(e) {}
return [{
  current_phase,
  request_id: parsed.request_id,
  client_id: parsed.client_id,
  campaign_brief: parsed.campaign_brief,
  priority: parsed.priority,
}];

